package main

import (
    "database/sql"
    "encoding/json"
    "fmt"
    "net/http"
    "log"
    _ "github.com/lib/pq"
)

type User struct {
    ID       int    `json:"id"`
    Username string `json:"username"`
    Email    string `json:"email"`
}

func searchUsersHandler(db *sql.DB) http.HandlerFunc {
    return func(w http.ResponseWriter, r *http.Request) {
        username := r.URL.Query().Get("username")
        if username == "" {
            http.Error(w, "username parameter is required", http.StatusBadRequest)
            return
        }

        query := "SELECT id, username, email FROM users WHERE username ILIKE $1"
        rows, err := db.Query(query, "%"+username+"%")
        if err != nil {
            log.Printf("Database query error: %v", err)
            http.Error(w, "Database query failed", http.StatusInternalServerError)
            return
        }
        defer rows.Close()

        var users []User
        for rows.Next() {
            var user User
            err := rows.Scan(&user.ID, &user.Username, &user.Email)
            if err != nil {
                log.Printf("Row scan error: %v", err)
                http.Error(w, "Failed to process results", http.StatusInternalServerError)
                return
            }
            users = append(users, user)
        }

        if err = rows.Err(); err != nil {
            log.Printf("Rows iteration error: %v", err)
            http.Error(w, "Failed to iterate results", http.StatusInternalServerError)
            return
        }

        w.Header().Set("Content-Type", "application/json")
        if err := json.NewEncoder(w).Encode(users); err != nil {
            log.Printf("JSON encoding error: %v", err)
            http.Error(w, "Failed to encode response", http.StatusInternalServerError)
            return
        }
    }
}

func main() {
    connStr := "user=postgres dbname=testdb sslmode=disable"
    db, err := sql.Open("postgres", connStr)
    if err != nil {
        log.Fatal(err)
    }
    defer db.Close()

    err = db.Ping()
    if err != nil {
        log.Fatal(err)
    }

    http.HandleFunc("/search", searchUsersHandler(db))
    log.Fatal(http.ListenAndServe(":8080", nil))
}